DbUtil = {}
DbUtil.GAME_DATA = 1
DbUtil.SUPPLY_BOX_DATA = 2
DbUtil.DEATH_SETTLEMENT = 3

DBManager:addMustLoadSubKey(DbUtil.GAME_DATA)
DBManager:addMustLoadSubKey(DbUtil.SUPPLY_BOX_DATA)
DBManager:addMustLoadSubKey(DbUtil.DEATH_SETTLEMENT)

DbUtil.FIRST_DATA_KEY = DbUtil.GAME_DATA
DbUtil.LAST_DATA_KEY = DbUtil.DEATH_SETTLEMENT

function DbUtil:getPlayerData(player)
    DBManager:getPlayerData(player.userId, DbUtil.GAME_DATA)
    DBManager:getPlayerData(player.userId, DbUtil.SUPPLY_BOX_DATA)
    DBManager:getPlayerData(player.userId, DbUtil.DEATH_SETTLEMENT)
end

function DbUtil:onPlayerGetDataFinish(player, data, subKey)
    if subKey == DbUtil.GAME_DATA then
        player.titles = data.titles or {}
        player.titleType = data.titleType or {}
        player.isNeedItemInit = data.isNeedItemInit
        player:initGameDataFromDB(data)
        player:PlayerItemInit()
        GameTitle:initTitle(player)
    end
    if subKey == DbUtil.DEATH_SETTLEMENT then
        player.lifeTime = data.lifeTime or 0 --登录时间
        player.killDeadNum = data.killDeadNum or 0
        player.killDeadScore = data.killDeadScore or 0
        player.killBossNum = data.killBossNum or 0 --击杀boss数
        player.killBossScore = data.killBossScore or 0
    end
    if subKey == DbUtil.SUPPLY_BOX_DATA then
        player:initSupplyDataFromDB(data)
    end
    if DbUtil:IsGetAllDataFinished(player) then
        player:initVIPBoxData()
        GameStore:syncSupplyData(player)
    end
end

function DbUtil:savePlayerData(player, immediate)
    if player == nil then
        return
    end
    DbUtil:SavePlayerGameData(player, immediate)
    DbUtil:SavePlayerSupplyBoxData(player, immediate)
    DbUtil:SavePlayerDeathSettlement(player, immediate)
end

function DbUtil:SavePlayerGameData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.GAME_DATA) then
        return
    end
    player:saveData()
    local data = {}
    data.titles = player.titles or {}
    data.titleType = player.titleType or {}
    data.isNeedItemInit = player.isNeedItemInit
    data.kills = player.kills or 0
    data.score = player.score or 0
    data.curHealth = player.curHealth or GameConfig.PlayerAttribute.MaxHealth
    data.curFoodLevel = player.curFoodLevel or GameConfig.PlayerAttribute.MaxFoodLevel
    data.curWaterLevel = player.curWaterLevel or GameConfig.PlayerAttribute.MaxWaterLevel
    data.lastSubWaterTime = player.lastSubWaterTime or 0
    data.closeDamage = player.closeDamage or GameConfig.PlayerAttribute.CloseDamage
    data.remoteDamage = player.remoteDamage or GameConfig.PlayerAttribute.RemoteDamage
    data.lastPosition = player.lastPosition or nil
    data.buffData = player.buffData or {}
    data.inventoryInfo = player.inventoryInfo or {}
    data.armorInventoryInfo = player.armorInventoryInfo or {}
    data.enderInventory = player.enderInventory or {}
    data.killMonsterNum = player.killMonsterNum or 0
    data.killPlayerNum = player.killPlayerNum or 0
    --data.loginDayCount = player.loginDayCount or WorldTimeManager.DayCount
    --player.surviveDays = WorldTimeManager.DayCount - player.loginDayCount
    data.surviveDays = player.surviveDays or 0 --存活天数
    data.vip_data = player.vip_data
    DBManager:savePlayerData(player.userId, DbUtil.GAME_DATA, data, immediate)
    HostApi.log(string.format("DbUtil:SavePlayerGameData rakssid:%s, immediate:%s",
            tostring(player.rakssid), tostring(immediate)))
end

function DbUtil:CanSavePlayerData(player, subKey)
    return DBManager:isLoadDataFinished(player.userId, subKey)
end

function DbUtil:SavePlayerSupplyBoxData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.SUPPLY_BOX_DATA) then
        return
    end
    local data = {}
    data.tiro_box = player.tiro_box
    data.daily_box = player.daily_box
    data.vip_box = player.vip_box
    data.vip_day_key = player.vip_day_key
    DBManager:savePlayerData(player.userId, DbUtil.SUPPLY_BOX_DATA, data, immediate)
end

function DbUtil:SavePlayerDeathSettlement(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.DEATH_SETTLEMENT) then
        return
    end
    local data = {}
    data.lifeTime = player.lifeTime or 0 --登录时间
    data.killDeadNum = player.killDeadNum or 0
    data.killDeadScore = player.killDeadScore or 0
    data.killBossNum = player.killBossNum or 0 --击杀boss数
    data.killBossScore = player.killBossScore or 0
    DBManager:savePlayerData(player.userId, DbUtil.DEATH_SETTLEMENT, data, immediate)
end

function DbUtil:IsGetAllDataFinished(player)
    for key = DbUtil.FIRST_DATA_KEY, DbUtil.LAST_DATA_KEY do
        if not DbUtil:CanSavePlayerData(player, key) then
            return false
        end
    end
    return true
end

return DbUtil